import json

reviews_data = locals()['var_function-call-3642866324570197762']
business_data_path = locals()['var_function-call-4054810070725982848']

if isinstance(business_data_path, str):
    with open(business_data_path, 'r') as f:
        business_data = json.load(f)
else:
    business_data = business_data_path

biz_desc_map = {b['business_id']: b['description'] for b in business_data}

def extract_categories(description):
    if not description:
        return []
    markers = [
        "services in ",
        "including ",
        "destination for "
    ]
    cat_string = None
    for marker in markers:
        if marker in description:
            parts = description.split(marker)
            if len(parts) > 1:
                cat_string = parts[-1]
                break
    if not cat_string:
        return []
    if cat_string.endswith('.'):
        cat_string = cat_string[:-1]
    raw_cats = cat_string.split(',')
    categories = []
    for rc in raw_cats:
        rc = rc.strip()
        if rc.lower().startswith('and '):
            rc = rc[4:].strip()
        if rc:
            categories.append(rc)
    return categories

ids_to_check = ['businessid_79', 'businessid_57', 'businessid_37', 'businessid_67', 'businessid_45']
debug_info = {}

for bid in ids_to_check:
    desc = biz_desc_map.get(bid, "NOT FOUND")
    cats = extract_categories(desc) if desc != "NOT FOUND" else []
    debug_info[bid] = {"desc": desc, "cats": cats}

print("__RESULT__:")
print(json.dumps(debug_info))

